var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"조디악 나이츠라고?","JPN":"ゾディアックナイツだと？","ENG":"The Zodiac Knights?","TWN":"十二宮騎士？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"네, 돌파 당하기 직전이던 동부 방어선에 나타나 침식체 공세를 막는 중이라고 합니다.","JPN":"はい、突破される直前だった東部の防御線に現われ、侵食体の攻撃を食い止めているそうです。","ENG":"Yes. We've received word that they've appeared at the eastern defense line that was about to fall and started fighting the C.O.s.","TWN":"是的，他們出現在即將被突破的東部防線上並擋住了侵蝕體的攻勢。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"코핀 컴퍼니의 호출을 받았다고 하는군요.","JPN":"なんでもコフィンカンパニーから呼び出されたとか。","ENG":"They said that Coffin Company called them.","TWN":"據說是接到了科芬公司的呼叫。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 양반… 기껏해야 건틀렛에서의 일면식이 전부일 텐데, 무슨 얘길 나눴길래 기사를 움직인 거야…?","JPN":"あいつ……ガントレットで一度会っただけのはずなのに、どんな話をしたら騎士が動き出すんだ……？","ENG":"Playing against them in Gauntlet should be the only time they've met... How did he convince the order to act...?","TWN":"他……頂多也只是在聖鎧見過一面，到底說了什麼話能讓他調動騎士……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"다른 곳 상황은 어떻지?","JPN":"他のところの状況は？","ENG":"How are the other areas doing?","TWN":"其他地方的情況如何？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"카운터 전력이 부족했던 서부 뉴 하이랜드는 메이드 복장을 한 카운터들의 지원을 받아 버티는 상황입니다.","JPN":"カウンターの戦力が不足していた西部のニューハイランドは、メイド服姿のカウンターたちに支援され、何とか持ちこたえています。","ENG":"Western New Highland didn't have enough Counter-power, but some Counters in maid costumes arrived as backup and they're holding out.","TWN":"西部新高地因為缺少制裁者戰力，目前在女僕裝扮的制裁者支援之下抗戰。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"침식체 방비가 가장 취약한 곳은 산간지대인 남동부 메리데일 방어선이었습니다만…","JPN":"侵食体への防備がもっとも弱いところは、山間地帯である南東部のメリーデール防御線だったのですが……","ENG":"The south-eastern Merrydale defense line, which is in the mountains, is the least prepared against C.O.s, but...","TWN":"侵蝕體防禦最薄弱的是山區東南部的梅里戴爾防線……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"방금 전, 무소속을 주장하는 카운터들이 방어전에 자원하면서 위기는 무사히 넘겼다더군요.","JPN":"先ほど、無所属を主張するカウンターたちが防御戦に志願し、無事危機を脱したそうです。","ENG":"They're out of the woods now after some Counters that claim to be independent have volunteered to help with the defense.","TWN":"剛才在一群自稱無所屬的制裁者們的支援下，防線順利度過了危機。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"사용하는 장비로 볼 때, 전수조사 중인 알파트릭스 이노베이션이 관여하고 있는 것 같습니다만… 감찰부에 관련 내용을 전달할까요?","JPN":"使用している装備からするに、全数調査中であるアルファトリックス・イノベーションが関与しているようですが……監察部に関連内容を伝えましょうか？","ENG":"Judging by their weapons, it looks like Alphatrix Innovation is involved. They're under extensive investigation at the moment... Should I relay the information to the Inspection Corps?","TWN":"根據她們使用的裝備來看，似乎是正在全數調查中的阿爾法崔克斯改革介入了……要不要轉告監察部？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"됐어. 그런 시시한 기싸움은 나중에 해도 늦지 않아.","JPN":"いや、いい。くだらない睨み合いは後からでも遅くない。","ENG":"Forget it. We can get to that power struggle later.","TWN":"算了吧，這些以後再說也不遲。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리자 권한도 장비도 전부 빼앗겨놓고 그렇게 여유만만 하더니…","JPN":"管理者権限も装備も全部奪われておいて、あれほど余裕があったのは……","ENG":"He was so composed, even after losing his Administrator authority and gear...","TWN":"管理者權限和裝備都被奪走了，還那麼悠悠哉哉的……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"허세가 아니었다는 거네?","JPN":"虚勢ではなかったというわけだな？","ENG":"I guess it wasn't just for show.","TWN":"竟然真的不是虛張聲勢？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"가브리엘 준 더 비셔스 브레이커! 이곳에 등장!","JPN":"ガブリエル・ジュン・ザ・ヴィシャス・ブレーカー！　ここに参上！","ENG":"Gabriel Jun the Vicious Breaker, present!","TWN":"加布里埃爾·朱恩·毀滅者！登場！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"칠색의 파사검을 쥔 심판자가 이곳에 있는 이상! 아무도 여긴 못 지나간다!","JPN":"七色の破邪剣を持つ審判者がここにいる以上！　何者も通さんぞ！","ENG":"As long as the arbiter wielding the Iridescent Evil-fighting Greatsword is here, no one shall pass!","TWN":"只要手持七色破邪劍的審判者在此，你們任何人都不許經過這裡！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GATE_NPC_CHARADE_NULL","text":{"KOREA":"저 꼬마는 뭐지? 한 발로 중심을 잡고 있을 뿐인데 침식체들이 넘어오질 못하고 있잖아?","JPN":"あのガキはなんだ？　一本足で立っているだけなのに、侵食体が近づけなくなってるぞ？","ENG":"What's with that kid? He's balancing on one foot, but the C.O.s can't get through him.","TWN":"那小鬼是誰？只是用一隻腳穩住重心而已，侵蝕體竟然無法越過她？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GATE_NPC_CHARADE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"가만히 서서 적의 공격을 막아내는 게 부동검법의 한계이자 장점이죠.","JPN":"じっと立ったまま、敵の攻撃を止めるのが不動剣法の限界であり、長所でもあります。","ENG":"It is the limit and the strong point of Stationary Swordsmanship to block enemy attacks while standing still.","TWN":"站在原地擋住敵人的攻擊既是不朽劍法的弱點，也是它的優勢。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"은행 강도도 쫓지 못하는 쓸모 없는 기술인 줄 알았는데, 요충지를 방어할 땐 제법 요긴하네요.","JPN":"銀行強盗さえ追えない役立たずの剣法だと思ってたのに、要地を防御する際には意外と使えますね。","ENG":"I thought it was a useless skill that couldn't even chase robbers, but it looks pretty handy when defending a key point.","TWN":"我原以為是一個連銀行強盜也無法制伏的沒用的技能，沒想到在防禦時能發揮這麼好的作用。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"합동공격으로 간다! 동생이여!","JPN":"合同攻撃で行こう！　妹よ！","ENG":"Get ready for a combo attack! Let's go, little sister!","TWN":"一起進攻吧！妹妹！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"흥, 누구 멋대로 동생이래? 누나인 내가 이번만 받아준다.","JPN":"ふん、誰が妹だって？　お姉さんである私が今回だけ許してあげるわ。","ENG":"Hmph, who are you calling little? As the older sister, I'll let it slide.","TWN":"哼，誰是你妹妹？姊姊這次先不跟你計較。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"하아앗!","JPN":"はああっ！","ENG":"Haaah!","TWN":"哈啊啊！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}}]`);export{e as default};